export function makeDefaultTableData() {
    return {
        rows: Array.from({ length: 4 }, () => ['', '', '', '']),
        colStyles: Array.from({ length: 4 }, () => ({ align: 'left', prefix: '', postfix: '', sumDecorator: false })),
        headingRow: false, headingCol: false, sumRow: false, sumCol: false,
    };
}
